import React, {useEffect, useState} from "react";
import {useLocation} from "react-router-dom";
import ReactPlayer from "react-player";
// import webproject1 from "../../resources/web-project-1.png";
import Modal from "react-modal";
const customStyles = {
    content : {
        top                   : '50%',
        left                  : '50%',
        right                 : 'auto',
        bottom                : 'auto',
        marginRight           : '-50%',
        transform             : 'translate(-50%, -50%)',
        width:"90%",
        height:"60%"
    }
};

const SoftwareProjects = ({config}) =>
{

    const location = useLocation();
    const [isProfession,SetProfession] = useState("");
    const [isShown, SetIsShown] = useState(false);
    const [isPlayable,SetPlayable] = useState(false);

    const [modalIsOpen,setIsOpen] = useState(false);
    useEffect(()=>{
        SetProfession(location.state.prof);
    },[location]);
    function detectMouse(n)
    {
        SetIsShown(n);
        SetPlayable(n);
    }
    function closeModal(modalN){
        SetIsShown(modalN);
        SetPlayable(modalN);
        setIsOpen(!modalN);
    }




    return (
        <div className="cell"
             onMouseEnter={() => (detectMouse(true))}
             onMouseLeave={() => (detectMouse(false))}
             onClick={()=>(detectMouse(true))}
        >
            {!modalIsOpen && (
                <div>
                    <button
                        className={`ui orange inverted button ${config.button}`}
                        onClick={() => setIsOpen(true)}
                        style={{opacity:isShown ? 1:0,transition: "opacity 1s",zIndex:"5"}}>Learn More</button>
                </div>
            )

            }

            <ReactPlayer
                url={config.projectURL}
                width='40vw'
                height='40vh'
                volume={1}
                muted={true}
                loop={false}
                playing={isPlayable ? false:true}
                // controls={isPlayable==1 ? 0 : 1}
                controls={true}
            ></ReactPlayer>
            {modalIsOpen && (
                <Modal
                    isOpen={modalIsOpen}
                    onRequestClose={()=>setIsOpen(false)}
                    style={customStyles}
                    contentLabel="Example Modal"

                >
                    <div className="ui segment" style={{width:"100%",height:"100%",zIndex:"6"}}>
                        <h2>{config.projectTitle}</h2>
                        <h4>Written in: {config.languageUsed} </h4>
                        <div className="grid">
                            <div className="cell">
                                <p>Check out the repository: </p>
                            </div>
                            <div className="cell">
                                <a href={config.repoURL} target="_blank">REPO</a>
                            </div>
                        </div>
                    </div>
                    <div className="ui vertical segment">
                        <button className="ui red inverted button" onClick={()=>closeModal(true)}>close</button>
                    </div>

                </Modal>
            )

            }
        </div>
    )

};
export default SoftwareProjects;
